insert into public.exercises
(title, description, category, difficulty, target_scores, body_issues, job_types, age_groups, video_url, thumbnail_url, caution, is_active)
values
('壁押し腕立て', '壁に手をついて、肘をゆっくり曲げ伸ばしします。握る力と上半身の土台づくりに。', '筋力', 'かんたん', array['筋力'], array['運動不足','疲れやすい'], array['デスクワーク','接客','医療介護'], array['20代','30代','40代','50代','60代以上'], null, null, '肩に痛みがある場合は浅い角度で行ってください。', true),
('タオル握り', '丸めたタオルを5秒握ってゆるめます。左右10回ずつが目安です。', '筋力', 'かんたん', array['筋力'], array['運動不足'], array['建設','製造','運送','その他'], array['20代','30代','40代','50代','60代以上'], null, null, '手首に違和感があれば力を弱めてください。', true),
('椅子スクワット', '椅子に座る直前で止まり、ゆっくり立ち上がります。下半身と体幹を同時に使います。', '筋力', 'ふつう', array['筋力','バランス'], array['ダイエット','運動不足','疲れやすい'], array['デスクワーク','接客','製造'], array['20代','30代','40代','50代','60代以上'], null, null, '膝が痛む場合は回数を減らしてください。', true),
('かかと上げ', '壁や椅子に軽く手を添え、かかとを上げ下げします。ふくらはぎとバランス感覚に効きます。', 'バランス', 'かんたん', array['バランス','筋力'], array['バランス不安','運動不足'], array['接客','医療介護','運送'], array['20代','30代','40代','50代','60代以上'], null, null, 'ふらつく場合は必ず支えを使ってください。', true),
('もも裏ストレッチ', '片脚を前に出して膝を軽く伸ばし、背中を丸めずに体を倒します。', '柔軟性', 'かんたん', array['柔軟性'], array['身体が硬い','腰痛'], array['デスクワーク','運送','製造'], array['20代','30代','40代','50代','60代以上'], null, null, '反動をつけず、気持ちよい範囲で止めてください。', true),
('股関節ゆらし', '椅子に座り、骨盤を前後に小さく動かします。腰まわりをやさしくほぐします。', '腰痛予防', 'かんたん', array['柔軟性','体幹'], array['腰痛','身体が硬い'], array['デスクワーク','運送'], array['30代','40代','50代','60代以上'], null, null, '強い痛みがある日は避けてください。', true),
('背中まるめ伸ばし', '四つばいで背中を丸める、反らす動きをゆっくり繰り返します。', '柔軟性', 'かんたん', array['柔軟性','体幹'], array['腰痛','肩こり','ストレス'], array['デスクワーク','医療介護','その他'], array['20代','30代','40代','50代','60代以上'], null, null, '腰を反らせすぎないようにしましょう。', true),
('首すじリセット', '片手を頭に添え、首の横をゆっくり伸ばします。左右20秒ずつ。', '肩こり', 'かんたん', array['柔軟性'], array['肩こり','ストレス'], array['デスクワーク','運送','接客'], array['20代','30代','40代','50代','60代以上'], null, null, '首を強く引っぱらないでください。', true),
('肩甲骨よせ', '両肘を後ろに引いて肩甲骨を寄せ、胸を開きます。10回ゆっくり行います。', '肩こり', 'かんたん', array['柔軟性'], array['肩こり','疲れやすい'], array['デスクワーク','医療介護','製造'], array['20代','30代','40代','50代','60代以上'], null, null, '肩がすくまないように意識してください。', true),
('支えあり片足立ち', '壁に指先を添えて片足立ちをします。10秒から始め、安定したら支えを減らします。', 'バランス', 'かんたん', array['バランス'], array['バランス不安','運動不足'], array['建設','製造','医療介護','接客'], array['30代','40代','50代','60代以上'], null, null, '転倒防止のため、必ず支えの近くで行ってください。', true),
('つま先かかと歩き', 'つま先立ちで数歩、かかと歩きで数歩を交互に行います。', 'バランス', 'ふつう', array['バランス','筋力'], array['バランス不安','ダイエット'], array['接客','建設','製造'], array['20代','30代','40代','50代'], null, null, '滑りにくい床で行ってください。', true),
('デッドバグ', '仰向けで手足を上げ、対角の手足をゆっくり伸ばします。腰を反らさないのがポイントです。', '体幹', 'ふつう', array['体幹','バランス'], array['腰痛','ダイエット','バランス不安'], array['デスクワーク','建設','製造'], array['20代','30代','40代','50代'], null, null, '腰が浮く場合は足だけ小さく動かしてください。', true),
('膝つきプランク', '肘と膝を床につき、頭から膝までをまっすぐ保ちます。まずは10秒から。', '体幹', 'ふつう', array['体幹','筋力'], array['腰痛','ダイエット','運動不足'], array['デスクワーク','建設','その他'], array['20代','30代','40代','50代'], null, null, '腰が落ちない範囲で短く行ってください。', true),
('4秒呼吸リセット', '4秒吸って、4秒吐く呼吸を1分続けます。緊張をほどきたい時に。', 'ストレス発散', 'かんたん', array['柔軟性'], array['ストレス','疲れやすい','肩こり'], array['デスクワーク','医療介護','接客','その他'], array['20代','30代','40代','50代','60代以上'], null, null, '息苦しさがあれば自然な呼吸に戻してください。', true),
('ステップタッチ', '左右に一歩ずつリズムよく移動します。軽い有酸素運動として始めやすい種目です。', '初心者向け', 'かんたん', array['バランス','筋力'], array['運動不足','ダイエット','ストレス'], array['デスクワーク','接客','その他'], array['20代','30代','40代','50代','60代以上'], null, null, '息が上がりすぎない速さで行ってください。', true),
('足首まわし', '椅子に座って足首を大きく回します。立つ前の準備運動にもおすすめです。', '初心者向け', 'かんたん', array['バランス'], array['バランス不安','疲れやすい'], array['運送','製造','医療介護','接客'], array['40代','50代','60代以上'], null, null, '足首に痛みがあれば小さく回してください。', true),
('ミニランジ', '片足を少し前に出し、浅く膝を曲げます。下半身の筋力と安定感を高めます。', '筋力', 'しっかり', array['筋力','バランス'], array['ダイエット','バランス不安'], array['建設','製造','接客'], array['20代','30代','40代','50代'], null, null, '膝が内側に入らないようにしましょう。', true),
('体側ストレッチ', '片手を上げて体を横に倒し、わき腹を伸ばします。左右20秒ずつ。', '柔軟性', 'かんたん', array['柔軟性'], array['身体が硬い','肩こり','ストレス'], array['デスクワーク','運送','その他'], array['20代','30代','40代','50代','60代以上'], null, null, '腰を反らせず、真横に倒してください。', true),
('ヒップリフト', '仰向けで膝を立て、お尻をゆっくり持ち上げます。腰を守るお尻の筋肉を使います。', '腰痛予防', 'ふつう', array['体幹','筋力'], array['腰痛','ダイエット'], array['デスクワーク','運送','製造'], array['20代','30代','40代','50代'], null, null, '腰を反らせて上げすぎないようにしてください。', true),
('その場足踏み', '姿勢を起こし、その場で軽く足踏みします。朝や休憩中の体力づくりに。', '初心者向け', 'かんたん', array['筋力','バランス'], array['運動不足','疲れやすい','ダイエット'], array['デスクワーク','医療介護','接客','その他'], array['20代','30代','40代','50代','60代以上'], null, null, 'ふらつく場合は椅子や壁の近くで行ってください。', true);
